Removing Useless Blocks

The indirect_jump optimisation removes blocks doing nothing except terminate
into another block, for instance b2 in factorial:

TEXT

 1fn f1(%v0, %v1) -> Int {
 2b0(%v0, %v1):
 3b1(%v0, %v1):
 4 %v2:Int = 0
 5 %v3:Bool = eq %v0, %v2
 6 br %v3, b2(%v0, %v1), b3(%v0, %v1)
 7b2(%v0, %v1):
 8 jmp b4(%v1)
 9b3(%v0, %v1):
10 %v4:Int = 1
11 %v5:Int = sub %v0, %v4
12 %v6:Int = mul %v0, %v1
13 %v7 = f1(%v5, %v6)
